mapper.select:
SELECT
    id, create_time, update_time, create_by, update_by, is_deleted,
    type, subtype, current_score, user_id
FROM t_member_credit_score_type
WHERE is_deleted = 0
  AND user_id = #{userId}
  AND type = #{type}
  AND subtype = #{subtype}
LIMIT 1

